UPDATE tb_role
   SET role_nm = #{roleNm}
	 , role_desc = #{roleDesc}
	 , use_flag = #{useFlag}
	 , upt_user_id  = #{uptUserId}
	 , upt_date_time  = now()
WHERE role_seq  = #{roleSeq}

UPDATE tb_role_user
   SET str_date = #{strDate}
	  ,end_date = #{endDate}
   	  ,use_flag = #{useFlag}
      ,upt_user_id  = #{uptUserId}
	  ,upt_date_time  = now()
WHERE role_user_seq=#{roleUserSeq}

UPDATE tb_role_user
   SET end_date = now()
   	  ,use_flag = false
   	  ,upt_user_id  = #{uptUserId}
	  ,upt_date_time  = now()
WHERE role_seq=#{roleSeq}

